import cadquery as cq

class ZRangeSelector(cq.Selector):
    def __init__(self, z_min, z_max):
        self.z_min = z_min
        self.z_max = z_max

    def filter(self, objectList):
        res = []
        for o in objectList:
            try:
                if o.geomType() == "CIRCLE":
                    center = o.Center()
                    if self.z_min <= center.z <= self.z_max:
                        res.append(o)
            except Exception:
                pass
        return res

